import type { Kudos, TeamMember } from "@prisma/client";
import { CategoryBadge } from "@/components/kudos/CategoryBadge";

export type KudosWithRelations = Kudos & {
  giver: TeamMember;
  recipient: TeamMember;
};

interface KudosCardProps {
  kudos: KudosWithRelations;
}

function formatDate(date: Date) {
  return new Intl.DateTimeFormat("en-US", {
    dateStyle: "medium",
    timeStyle: "short",
  }).format(date);
}

export function KudosCard({ kudos }: KudosCardProps) {
  const giverName = kudos.giver.displayName ?? kudos.giver.name;
  const recipientName = kudos.recipient.displayName ?? kudos.recipient.name;

  return (
    <article
      className="rounded-lg border border-[#d8d9db] bg-white p-4 shadow-sm"
      aria-label={`Kudos from ${giverName} to ${recipientName}`}
    >
      <div className="flex flex-wrap items-center gap-2 text-sm text-[#3d4657]">
        <span className="font-medium text-[#212631]">{giverName}</span>
        <span aria-hidden="true">→</span>
        <span className="font-medium text-[#212631]">{recipientName}</span>
        <CategoryBadge category={kudos.category} className="ml-1" />
      </div>
      <p className="mt-2 text-[#212631]">{kudos.message}</p>
      <time
        dateTime={kudos.createdAt.toISOString()}
        className="mt-2 block text-xs text-[#8a8c91]"
      >
        {formatDate(kudos.createdAt)}
      </time>
    </article>
  );
}
