import { getKudosFeed } from "@/lib/feed";
import { KudosCard } from "@/components/kudos/KudosCard";

export default async function FeedPage() {
  const kudos = await getKudosFeed();

  return (
    <div className="min-h-full bg-[#f5f6f8]">
      <div className="max-w-3xl mx-auto px-4 py-8">
        <h1 className="text-2xl font-semibold text-[#212631]">Feed</h1>
        <p className="mt-1 text-sm text-[#66686c]">
          All kudos in reverse chronological order. Everyone sees the same feed.
        </p>

        {kudos.length === 0 ? (
          <div
            className="mt-8 rounded-lg border border-[#d8d9db] bg-white p-8 text-center"
            role="status"
            aria-live="polite"
          >
            <p className="text-[#3d4657]">No kudos yet.</p>
            <p className="mt-1 text-sm text-[#8a8c91]">
              Be the first to give someone recognition.
            </p>
          </div>
        ) : (
          <ul className="mt-6 space-y-4" aria-label="Kudos feed">
            {kudos.map((item) => (
              <li key={item.id}>
                <KudosCard kudos={item} />
              </li>
            ))}
          </ul>
        )}
      </div>
    </div>
  );
}
